#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long n;
        scanf("%lld", &n);
        if (n > 0) {
            printf("Positive");
        } else if (n < 0) {
            printf("Negative");
        } else {
            printf("Zero");
        }
        if (T) printf("\n");
    }
    return 0;
}

